#!/usr/bin/env python3
"""
CI/CD pip install script for automated deployment pipeline.
Installs all requirements from requirements.txt with upgrade flag for latest versions.
"""

import subprocess
import sys
import os


def check_requirements_file(filepath="requirements.txt"):
    """Check if requirements file exists and is readable."""
    if not os.path.isfile(filepath):
        print(f"ERROR: {filepath} not found in {os.getcwd()}")
        sys.exit(1)
    if os.path.getsize(filepath) == 0:
        print(f"WARNING: {filepath} is empty. No packages to install.")
        return False
    return True


def upgrade_pip():
    """Upgrade pip itself to the latest version."""
    print("=" * 60)
    print("Upgrading pip to latest version...")
    print("=" * 60)
    result = subprocess.run(
        [
            sys.executable, "-m", "pip", "install",
            "--upgrade", "pip"
        ],
        capture_output=True,
        text=True
    )
    if result.returncode != 0:
        print(f"WARNING: Failed to upgrade pip: {result.stderr}")
    else:
        print("pip upgraded successfully.")
    return result.returncode


def install_requirements(filepath="requirements.txt"):
    """
    Install all packages from requirements.txt with --upgrade flag.
    Uses --no-cache-dir for clean installs and --upgrade for latest versions.
    Hash verification is not used for speed in CI/CD.
    """
    print("=" * 60)
    print(f"Installing requirements from {filepath}")
    print("=" * 60)

    cmd = [
        sys.executable, "-m", "pip", "install",
        "-r", filepath,
        "--upgrade",
        "--no-cache-dir",
        "--require-hashes=false" if False else "",  # noqa - hash verification disabled for speed
    ]
    # Remove empty strings from command
    cmd = [c for c in cmd if c]

    # Build the actual command
    cmd = [
        sys.executable, "-m", "pip", "install",
        "-r", filepath,
        "--upgrade",
        "--no-cache-dir",
    ]

    print(f"Running: {' '.join(cmd)}")
    print("-" * 60)

    result = subprocess.run(
        cmd,
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT
    )

    print(result.stdout)

    if result.returncode != 0:
        print(f"ERROR: pip install failed with exit code {result.returncode}")
        sys.exit(result.returncode)

    print("-" * 60)
    print("All requirements installed successfully.")
    return result.returncode


def list_installed_packages():
    """List all installed packages for verification/logging."""
    print("=" * 60)
    print("Installed packages:")
    print("=" * 60)
    result = subprocess.run(
        [sys.executable, "-m", "pip", "list", "--format=columns"],
        capture_output=True,
        text=True
    )
    if result.returncode == 0:
        print(result.stdout)
    else:
        print(f"WARNING: Could not list packages: {result.stderr}")


def main():
    """Main entry point for CI/CD dependency installation."""
    print("=" * 60)
    print("CI/CD Dependency Installation Script")
    print(f"Python: {sys.version}")
    print(f"Working Directory: {os.getcwd()}")
    print("=" * 60)

    # Allow custom requirements file path via command line argument
    requirements_file = "requirements.txt"
    if len(sys.argv) > 1:
        requirements_file = sys.argv[1]

    # Step 1: Check requirements file exists
    if not check_requirements_file(requirements_file):
        print("Nothing to install. Exiting.")
        sys.exit(0)

    # Step 2: Upgrade pip
    upgrade_pip()

    # Step 3: Install all requirements with upgrade flag
    install_requirements(requirements_file)

    # Step 4: List installed packages for CI/CD logs
    list_installed_packages()

    print("=" * 60)
    print("Dependency installation complete.")
    print("=" * 60)


if __name__ == "__main__":
    main()